choose.when:
SELECT pi.product_id, p.product_name, p.unit, pi.lot_no, GREATEST(SUM(COALESCE(pi.inbound_qty, 0)) - SUM(COALESCE(po.outbound_qty, 0)), 0) AS stock_qty, 50 AS safe_qty, MIN(pi.reg_date) AS reg_date, MAX(pi.expire_date) AS expire_date FROM product_inbound pi JOIN product p ON pi.product_id = p.product_id LEFT JOIN product_outbound po ON pi.product_id = po.product_id AND pi.lot_no = po.lot_no
(p.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi.reg_date >= #{startDate}
AND pi.reg_date <= #{endDate}
GROUP BY pi.product_id, p.product_name, p.unit, pi.lot_no ORDER BY reg_date DESC

choose.otherwise:
SELECT t.product_id, t.product_name, t.unit, t.lot_no, t.stock_qty, 50 AS safe_qty, t.reg_date, t.expire_date FROM ( -- 현재고 있는 LOT 전부 SELECT pi.product_id, p.product_name, p.unit, pi.lot_no, GREATEST(SUM(COALESCE(pi.inbound_qty, 0)) - SUM(COALESCE(po.outbound_qty, 0)), 0) AS stock_qty, MIN(pi.reg_date) AS reg_date, MAX(pi.expire_date) AS expire_date FROM product_inbound pi JOIN product p ON pi.product_id = p.product_id LEFT JOIN product_outbound po ON pi.product_id = po.product_id AND pi.lot_no = po.lot_no
p.product_name IN ('돼지국밥', '순대국밥', '한우곰탕')
(p.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi.reg_date >= #{startDate}
AND pi.reg_date <= #{endDate}
GROUP BY pi.product_id, p.product_name, p.unit, pi.lot_no HAVING stock_qty > 0
UNION ALL
-- 현재고가 전부 0인 제품의 가장 최근 1건만 SELECT sub.product_id, sub.product_name, sub.unit, sub.lot_no, 0 AS stock_qty, sub.reg_date, sub.expire_date FROM ( SELECT pi2.product_id, p2.product_name, p2.unit, pi2.lot_no, MIN(pi2.reg_date) AS reg_date, MAX(pi2.expire_date) AS expire_date, ROW_NUMBER() OVER (PARTITION BY pi2.product_id ORDER BY MIN(pi2.reg_date) DESC) AS rn, GREATEST(SUM(COALESCE(pi2.inbound_qty, 0)) - SUM(COALESCE(po2.outbound_qty, 0)), 0) AS stock_qty FROM product_inbound pi2 JOIN product p2 ON pi2.product_id = p2.product_id LEFT JOIN product_outbound po2 ON pi2.product_id = po2.product_id AND pi2.lot_no = po2.lot_no
p2.product_name IN ('돼지국밥', '순대국밥', '한우곰탕')
(p2.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi2.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi2.reg_date >= #{startDate}
AND pi2.reg_date <= #{endDate}
GROUP BY pi2.product_id, p2.product_name, p2.unit, pi2.lot_no HAVING stock_qty = 0 ) sub WHERE sub.rn = 1 AND NOT EXISTS ( SELECT 1 FROM product_inbound pi3 LEFT JOIN product_outbound po3 ON pi3.product_id = po3.product_id AND pi3.lot_no = po3.lot_no WHERE pi3.product_id = sub.product_id GROUP BY pi3.product_id, pi3.lot_no HAVING GREATEST(SUM(COALESCE(pi3.inbound_qty, 0)) - SUM(COALESCE(po3.outbound_qty, 0)), 0) > 0 )
) t
ORDER BY CASE WHEN t.stock_qty > 0 THEN 0 ELSE 1 END, t.reg_date DESC

mapper.update:
UPDATE product_stock
SET stock_qty = GREATEST(stock_qty - #{qty}, 0)
WHERE product_id = #{productId} AND lot_no = #{lotNo}

mapper.select:
SELECT reg_date, type, qty, memo
FROM product_stock_transaction
WHERE product_id = #{productId}
  AND lot_no = #{lotNo}
ORDER BY reg_date DESC
